const path = require("path");
const fs = require("fs");

const problemsFile = path.resolve(__dirname, "../../data/problems.json");

function loadProblems() {
	try {
		const data = fs.readFileSync(problemsFile, "utf8");
		return JSON.parse(data);
	} catch (e) {
		return [];
	}
}

function getProblemById(problemId) {
	const problems = loadProblems();
	return problems.find(p => p.id === problemId);
}

function aggregateComponentStats(problem) {
	if (!problem || !problem.components) return null;

	const languageCounts = {};
	const statusCounts = {};
	let maxPoints = 0;

	for (const comp of problem.components) {
		if (comp.language) {
			languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
		}
		if (comp.status) {
			statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
		}
		if (typeof comp.points === "number" && comp.points > maxPoints) {
			maxPoints = comp.points;
		}
	}

	return {
		languageCounts,
		statusCounts,
		maxPoints
	};
}

async function getProblemDetail(problemId) {
	const problem = getProblemById(problemId);
	if (!problem) {
		const error = new Error("Problem not found");
		error.status = 404;
		throw error;
	}
	const componentStats = aggregateComponentStats(problem);
	return {
		...problem,
		componentStats
	};
}

module.exports = {
	getProblemDetail
};
